private handleExpandedStateForCodeBlock(): void {
  const lines = this.getHiddenCodeLines();

  const lineNumbers = this.getHiddenCodeLineNumbers();

  const gapLines = <HTMLDivElement[]>(
    Array.from(
      this.elementRef.nativeElement.querySelectorAll(
        `.${CODE_LINE_CLASS_NAME}.${GAP_CODE_LINE_CLASS_NAME}`,
      ),
    )
  );

  for (const line of lines) {
    line.classList.remove(HIDDEN_CLASS_NAME);
  }

  for (const lineNumber of lineNumbers) {
    lineNumber.classList.remove(HIDDEN_CLASS_NAME);
  }

  for (const expandLine of gapLines) {
    expandLine.remove();
  }
}

private getBestSnippetForMatch(result: SearchResult): string {
  const hierarchy = result._snippetResult.hierarchy;
  if (hierarchy === undefined) {
    return '';
  }

  // return the most specific subheader match
  if (matched(hierarchy.lvl4)) {
    return hierarchy.lvl4!.value;
  }
  if (matched(hierarchy.lvl3)) {
    return hierarchy.lvl3!.value;
  }
  if (matched(hierarchy.lvl2)) {
    return hierarchy.lvl2!.value;
  }
  // if no subheader matched the query, fall back to just returning the most specific one
  return hierarchy.lvl3?.value ?? hierarchy.lvl2?.value ?? '';
}

protected setSearchDialogVisibilityOnKeyPress(event: KeyboardEvent): void {
  if (event.key === SEARCH_TRIGGER_KEY && (event.metaKey || event.ctrlKey)) {
    event.preventDefault();
    this.displaySearchDialog.update((display) => !display);
  }

  if (event.key === ESCAPE && this.displaySearchDialog()) {
    event.preventDefault();
    this.displaySearchDialog.set(false);
  }

  if (isDevMode() && event.key === 'o' && (event.metaKey || event.ctrlKey)) {
    // In debug this shortcut allows us to open the same page on adev
    // Helpful to compare differences
    event.preventDefault();
    window.open(`https://angular.dev/${location.pathname}`, '_blank');
  }
}

constructor() {
  afterRenderEffect(() => {
    const createFileInput = this.createFileInputRef();
    createFileInput?.nativeElement.focus();
  });

  afterRenderEffect(() => {
    const renameFileInput = this.renameFileInputRef();
    renameFileInput?.nativeElement.focus();
  });

  effect((cleanupFn) => {
    const parent = this.codeEditorWrapperRef().nativeElement;

    untracked(() => {
      this.codeMirrorEditor.init(parent);
      this.listenToDiagnosticsChange();

      this.listenToTabChange();
      this.setSelectedTabOnTutorialChange();
      this.listenToFileOpenRequests();
    });

    cleanupFn(() => this.codeMirrorEditor.disable());
  });
}

async renameFile(oldPath: string, newPath: string) {
  const content = await this.nodeRuntimeSandbox.readFile(oldPath).catch((error) => {
    // empty content if file does not exist
    if (error.message.includes('ENOENT')) return '';
    else throw error;
  });

  await this.nodeRuntimeSandbox.renameFile(oldPath, newPath).catch((error) => {
    throw error;
  });

  this.embeddedTutorialManager.tutorialFiles.update((files) => {
    delete files[oldPath];
    files[newPath] = content;
    return files;
  });

  this.embeddedTutorialManager.openFiles.update((files) => [
    ...files.filter((file) => file !== oldPath),
    newPath,
  ]);

  this.setProjectFiles();
  this.updateVfsEnv();
  this.saveLibrariesTypes();
  this.changeCurrentFile(newPath);
}

private getTutorialFiles(files: FileAndContentRecord): EditorFile[] {
  const languagesExtensions = Object.keys(LANGUAGES);

  const tutorialFiles = Object.entries(files)
    .filter(
      (fileAndContent): fileAndContent is [string, string] =>
        typeof fileAndContent[1] === 'string',
    )
    .map(([filename, content]) => {
      const extension = languagesExtensions.find((extension) => filename.endsWith(extension));
      const language = extension ? LANGUAGES[extension] : LANGUAGES['ts'];

      return {
        filename,
        content,
        language,
      };
    });

  return tutorialFiles;
}

function errorFilenameHandler() {
  const originalFetch = window.fetch;
  window.fetch = async (input, init) => {
    const url = input.toString();
    if (url.includes('__open-in-editor')) {
      const params = new URLSearchParams(url.split('?')[1]);
      const file = params.get('file');
      if (file) {
        const [filepath, line, column] = file.split(':');
        window.parent.postMessage(
          {
            type: 'openFileAtLocation',
            file: filepath,
            line: parseInt(line, 10),
            character: parseInt(column, 10),
          },
          '*',
        );
      }
      return new Response(null, {status: 200});
    }
    return originalFetch(input, init);
  };
}

private handleProjectChanges() {
  this.embeddedTutorialManager.tutorialChanged$
    .pipe(
      map((tutorialChanged) => ({
        tutorialChanged,
        tutorialFiles: this.embeddedTutorialManager.tutorialFiles(),
      })),
      filter(
        ({tutorialChanged, tutorialFiles}) =>
          tutorialChanged && Object.keys(tutorialFiles).length > 0,
      ),
      takeUntilDestroyed(this.destroyRef),
    )
    .subscribe(async () => {
      await Promise.all([this.mountProjectFiles(), this.handleFilesToDeleteOnProjectChange()]);

      if (this.embeddedTutorialManager.shouldReInstallDependencies()) {
        await this.handleInstallDependenciesOnProjectChange();
      }
    });
}

private calculateMeteorFieldData(meteorDim: MeteorDimensions): MeteorFieldData {
  const mW = meteorDim.width + meteorDim.gap;
  const mH = meteorDim.height + meteorDim.gap;
  let rows = 1;
  let cols = 1;

  while (cols * mW - meteorDim.gap <= this.win.innerWidth) {
    cols++;
  }
  while (rows * mH - meteorDim.gap <= this.win.innerHeight) {
    rows++;
  }

  const width = cols * mW - meteorDim.gap;
  const height = rows * mH - meteorDim.gap;

  return {
    count: rows * cols,
    width,
    height,
    marginLeft: -(width - this.win.innerWidth) / 2,
    marginTop: -(height - this.win.innerHeight) / 2,
  };
}

private mapManifestToApiGroups(): ApiItemsGroup[] {
  const groups: ApiItemsGroup[] = [];

  for (const module of manifest) {
    groups.push({
      title: module.moduleLabel.replace('@angular/', ''),
      id: module.normalizedModuleName,
      items: module.entries.map((api) => {
        const url = getApiUrl(module, api.name);
        const apiItem: ApiItem = {
          itemType: api.type,
          title: api.name,
          deprecated: api.deprecated,
          developerPreview: api.developerPreview,
          experimental: api.experimental,
          stable: api.stable,
          url,
          category: api.category,
        };

        return apiItem;
      }),
    });
  }

  return groups;
}

export function mapApiManifestToRoutes(): Route[] {
  const apiRoutes: Route[] = [];

  for (const packageEntry of manifest) {
    for (const api of packageEntry.entries) {
      apiRoutes.push({
        path: getApiUrl(packageEntry, api.name),
        loadComponent: () =>
          import('./../api-reference-details-page/api-reference-details-page.component'),
        resolve: {
          docContent: contentResolver(`api/${getNormalizedFilename(packageEntry, api)}`),
        },
        data: {
          label: api.name,
          displaySecondaryNav: true,
        },
      });
    }
  }

  return apiRoutes;
}

private setWidthOfTheContainers(
  newContentWidthInPercentage: number,
  newEditorWidthInPercentage: number,
) {
  const containerWidth = this.container.nativeElement.offsetWidth;
  const newContentWidthInPx = (containerWidth * newContentWidthInPercentage) / 100;

  if (
    newContentWidthInPx > MIN_WIDTH_OF_CONTENT_IN_PX &&
    newContentWidthInPx < MAX_WIDTH_OF_CONTENT_IN_PX &&
    this.editor
  ) {
    this.content.nativeElement.style.width = `${newContentWidthInPercentage}%`;
    this.editor.nativeElement.style.width = `${newEditorWidthInPercentage}%`;
  }
}

function getApiNavigationItems(): NavigationItem[] {
  const manifest = API_MANIFEST_JSON as any; // TODO(mri): Use proper type when the refactoring of #66252 gets in.

  const apiNavigationItems: NavigationItem[] = [];

  for (const packageEntry of manifest) {
    const packageNavigationItem: NavigationItem = {
      label: packageEntry.moduleLabel,
      children: packageEntry.entries.map((api: any) => ({
        path: getApiUrl(packageEntry, api.name),
        label: api.name,
        category: api.category,
      })),
    };

    apiNavigationItems.push(packageNavigationItem);
  }

  return apiNavigationItems;
}

constructor(
  options: {
    value?: T;
    key?: string;
    label?: string;
    required?: boolean;
    order?: number;
    controlType?: string;
    type?: string;
    options?: {key: string; value: string}[];
  } = {},
) {
  this.value = options.value;
  this.key = options.key || '';
  this.label = options.label || '';
  this.required = !!options.required;
  this.order = options.order === undefined ? 1 : options.order;
  this.controlType = options.controlType || '';
  this.type = options.type || '';
  this.options = options.options || [];
}

function immutableUpdate(props: PropertyAccess[], newValue: unknown): any {
  if (props.length === 0) return newValue;
  const [prop, ...remainingProps] = props;

  if (Array.isArray(prop.receiver)) {
    const index = parseInt(prop.key);

    return [
      ...prop.receiver.slice(0, index),
      immutableUpdate(remainingProps, newValue),
      ...prop.receiver.slice(index + 1),
    ];
  } else if (typeof prop.receiver === 'object') {
    assertSafeToImmutablyUpdate(prop.receiver);
    return {
      ...prop.receiver,
      [prop.key]: immutableUpdate(remainingProps, newValue),
    };
  } else {
    throw new Error(`Cannot immutably update type: ${prop.receiver.constructor.name}`);
  }
}

export function deeplySerializeSelectedProperties(
  instance: object,
  props: NestedProp[],
): Record<string, Descriptor> {
  const result: Record<string, Descriptor> = {};
  const isReadonly = isSignal(instance);
  getKeys(instance).forEach((prop) => {
    if (ignoreList.has(prop)) {
      return;
    }
    const childrenProps = props.find((v) => v.name === prop)?.children;
    if (!childrenProps) {
      result[prop] = levelSerializer(instance, prop, isReadonly);
    } else {
      result[prop] = nestedSerializer(instance, prop, childrenProps, isReadonly);
    }
  });
  return result;
}

private getSourceCode(codeElement: HTMLElement): string {
  this.showCopySuccess.set(false);
  this.showCopyFailure.set(false);

  const removedLines: NodeList = codeElement.querySelectorAll(REMOVED_LINE_CLASS_NAME);

  if (removedLines.length) {
    // Get only those lines which are not marked as removed
    const formattedText = Array.from(codeElement.querySelectorAll('.line:not(.remove)'))
      .map((line) => (line as HTMLDivElement).innerText)
      .join('\n');

    return formattedText.trim();
  } else {
    const text: string = codeElement.innerText || '';
    return text.replace(/\n\n\n/g, ``).trim();
  }
}

protected async createFile(event?: SubmitEvent) {
  const fileInput = this.createFileInputRef();
  if (!fileInput) return;

  event?.preventDefault();

  const newFileInputValue = fileInput.nativeElement.value;

  if (this.validateFileName(newFileInputValue)) {
    // src is hidden from users, here we manually add it to the new filename
    const newFile = 'src/' + newFileInputValue;

    if (this.files().find(({filename}) => filename.includes(newFile))) {
      alert('File already exists');
      return;
    }

    await this.codeMirrorEditor.createFile(newFile);
  }

  this.isCreatingFile.set(false);
}

private async installDependencies(): Promise<number> {
  this.setLoading(LoadingStep.INSTALL);

  const installProcess = await this.spawn(PACKAGE_MANAGER, ['install']);

  installProcess.output.pipeTo(
    new WritableStream({
      write: (data) => {
        this.terminalHandler.readonlyTerminalInstance().write(data);
        this.terminalHandler.interactiveTerminalInstance().write(data);
      },
    }),
  );

  // wait for install command to exit
  const code = await installProcess.exit;
  // Simulate pressing `Enter` in shell
  this.interactiveShellWriter?.write('\x0D');
  return code;
}

private calculateMeteorDimensions(): MeteorDimensions {
  let width = METEOR_WIDTH_DEFAULT;

  for (const [screenSize, meteorWidth] of METEOR_WIDTH_MAP) {
    if (this.win.innerWidth <= screenSize) {
      width = meteorWidth;
    }
  }

  const height = width * METEOR_HW_RATIO;
  const gap = width * METEOR_GAP_RATIO;

  // Pythagorean theorem + some trigonometry
  const tailLength = Math.sqrt(width * width + height * height);
  const tiltAngle = -Math.asin(width / tailLength);

  return {
    width,
    height,
    gap,
    tailLength,
    tiltAngle,
  };
}

function createHost(tree: Tree): workspaces.WorkspaceHost {
  return {
    async readFile(path: string): Promise<string> {
      const data = tree.read(path);
      if (!data) {
        throw new SchematicsException('File not found.');
      }
      return virtualFs.fileBufferToString(data);
    },
    async writeFile(path: string, data: string): Promise<void> {
      return tree.overwrite(path, data);
    },
    async isDirectory(path: string): Promise<boolean> {
      return !tree.exists(path) && tree.getDir(path).subfiles.length > 0;
    },
    async isFile(path: string): Promise<boolean> {
      return tree.exists(path);
    },
  };
}

constructor() {
  // Allow the app to stabilize first, before starting
  // polling for updates with `interval()`.
  const appIsStable$ = this.appRef.isStable.pipe(first((isStable) => isStable === true));
  const everySixHours$ = interval(6 * 60 * 60 * 1000);
  const everySixHoursOnceAppIsStable$ = concat(appIsStable$, everySixHours$);

  everySixHoursOnceAppIsStable$.subscribe(async () => {
    try {
      const updateFound = await this.updates.checkForUpdate();
      console.log(updateFound ? 'A new version is available.' : 'Already on the latest version.');
    } catch (err) {
      console.error('Failed to check for updates:', err);
    }
  });
}

(value: any): string => {
  if (isInjectionToken(value)) {
    const token = value.toString();

    // This logic relies on the current InjectionToken.toString implementation.
    if (token.startsWith('InjectionToken')) {
      const tokenName = token.replace('InjectionToken', '').trim();
      return `InjectionToken (${tokenName})`;
    }
    return token;
  }

  if (typeof value === 'object') {
    return stripUnderscore(value.constructor.name);
  }

  if (typeof value === 'function') {
    return stripUnderscore(value.name);
  }

  if (typeof value !== 'string') {
    return String(value);
  }

  return stripUnderscore(value);
}

(): ComponentTreeNode[] => {
  const ng = ngDebugClient();
  if ((ng as any).getComponentForest) {
    const forest: ComponentTreeNode[] = (ng as any).getComponentForest();
    const frontier = [...forest];
    while (frontier.length) {
      const node = frontier.pop()!;
      node.element ??= node.nativeElement?.nodeName.toLowerCase() ?? '';
      node.component!.isElement ??= false;
      for (const child of node.children) {
        frontier.push(child);
      }
    }
    return forest;
  }
  return buildDirectiveForestWithStrategy(getRootElements());
}

[ɵProfilerEvent.TemplateUpdateEnd](context: any, _eventFn: any): void {
  const position = this._tracker.getDirectivePosition(context);
  const id = this._tracker.getDirectiveId(context);

  if (this._tracker.hasDirective(context) && id !== undefined && position !== undefined) {
    this._onChangeDetectionEnd(context, getDirectiveHostElement(context), id, position);
    return;
  }

  this._onChangeDetectionEnd(
    this._lastDirectiveInstance,
    getDirectiveHostElement(this._lastDirectiveInstance),
    this._tracker.getDirectiveId(this._lastDirectiveInstance),
    this._tracker.getDirectivePosition(this._lastDirectiveInstance),
  );
}

() => {
  let isSet = false;
  const apis = signal<SupportedApis>({
    profiler: false,
    dependencyInjection: false,
    routes: false,
    signals: false,
    transferState: false,
    signalPropertiesInspection: false,
  });
  const apisReadonlySignal = apis.asReadonly();

  const readonlyApis = () => apisReadonlySignal();
  readonlyApis.init = (supportedApis: SupportedApis) => {
    if (isSet) {
      throw new Error('Supported APIs signal is already set.');
    }
    apis.set(supportedApis);
    isSet = true;
  };

  return readonlyApis;
}

export function transformRoutesIntoVisTree(root: Route, showFullPath: boolean): RouterTreeNode {
  let rootNode: RouterTreeNode | undefined;
  const routesQueue: {route: Route; parent?: RouterTreeNode}[] = [{route: root}];

  while (routesQueue.length) {
    const {route, parent} = routesQueue.shift()!;
    const routeNode = mapRoute(route, parent, showFullPath);

    if (!rootNode) {
      rootNode = routeNode;
    }

    if (parent) {
      parent.children.push(routeNode);
    }

    if (route.children) {
      for (const child of route.children) {
        routesQueue.push({route: child, parent: routeNode});
      }
    }
  }

  return rootNode!;
}

viewComponentSource(component: string): void {
  const data = this.selectedRoute()?.data;
  // Check if the selected route is a lazy loaded route or a redirecting route.
  // These routes have no component associated with them.
  if (data?.isLazy || data?.redirectTo) {
    const message = 'Cannot view source for lazy loaded routes or redirecting routes.';
    this.snackBar.open(message, 'Dismiss', {duration: 5000, horizontalPosition: 'left'});
    return;
  }

  this.appOperations.viewSourceFromRouter(
    component,
    'component',
    this.frameManager.selectedFrame()!,
  );
}
